function numRabbits(answers) {
    let count = {};
    let res = 0;
    for (let a of answers) {
        count[a] = count[a] ? count[a] + 1 : 1;
        if (count[a] === 1) {
            res += (a + 1);
        } else if (count[a] > a + 1) {
            count[a] = 1;
            res += (a + 1);
        }
    }
    return res;
}
```


