import java.util.HashMap;
public int numRabbits(int[] answers) {
    HashMap<Integer, Integer> count = new HashMap<>();
    int res = 0;
    for (int a : answers) {
        count.put(a, count.getOrDefault(a, 0) + 1);
        if (count.get(a) == 1) {
            res += (a + 1);
        } else if (count.get(a) > a + 1) {
            count.put(a, 1);
            res += (a + 1);
        }
    }
    return res;
}
```


